import{_ as s,o as a,c as n,ag as e}from"./chunks/framework.BZohXCq9.js";const o="/assets/tutorial-system-entry.C2RWbL8q.png",r="/assets/tutorial-greeting.C2QMy0mg.png",d="/assets/tutorial-variables.Cxh0rpaj.png",p="/assets/tutorial-studio-ai2.D2UO9Nvp.png",l="/assets/tutorial-studio-result.BkcBCiJx.png",i="/assets/tutorial-publish.DJSuwanr.png",k=JSON.parse('{"title":"手把手教程：从零做一个生存恐怖世界","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/02-tutorial-basic.md","filePath":"creator-guide/02-tutorial-basic.md","lastUpdated":null}'),c={name:"creator-guide/02-tutorial-basic.md"};function g(h,t,u,b,m,q){return a(),n("div",null,[...t[0]||(t[0]=[e('<h1 id="手把手教程-从零做一个生存恐怖世界" tabindex="-1">手把手教程：从零做一个生存恐怖世界 <a class="header-anchor" href="#手把手教程-从零做一个生存恐怖世界" aria-label="Permalink to &quot;手把手教程：从零做一个生存恐怖世界&quot;">​</a></h1><p>我们要做一个类似 <strong>&quot;No, I&#39;m not a Human&quot;</strong> 的恐怖生存游戏。玩法很简单：末日降临，外面有伪装成人类的&quot;访客&quot;。你独自在家，每晚都有人来敲门。透过猫眼判断来者是人是怪，做出选择，活过14天。</p><p>做完这篇教程，你就掌握了 Yumina 最核心的创作技能——词条、变量、指令、组件、世界书。不管以后做什么类型的世界，都从这里起步 (•̀ᴗ•́)و</p><hr><h2 id="第一步-创建新世界" tabindex="-1">第一步：创建新世界 <a class="header-anchor" href="#第一步-创建新世界" aria-label="Permalink to &quot;第一步：创建新世界&quot;">​</a></h2><p>点击左侧导航栏的 <strong>创建（Create）</strong> 按钮，选 <strong>空白项目（Blank Project）</strong>。进入编辑器后，在左上角输入框填好世界名称：</p><ul><li><strong>名称</strong>：<code>伪人</code></li></ul><p>如果你还不熟悉编辑器的各个区域，可以先去 <a href="./01-beginner-guide.html">新手指南</a> 逛一圈再回来。</p><hr><h2 id="第二步-写角色设定词条" tabindex="-1">第二步：写角色设定词条 <a class="header-anchor" href="#第二步-写角色设定词条" aria-label="Permalink to &quot;第二步：写角色设定词条&quot;">​</a></h2><p>点左侧导航栏的 <strong>词条（Lorebook）</strong>。</p><p>你会看到左边有几个分组，其中 <strong>PRESETS</strong>（预设区）里已经有一些 Yumina 官方的预设词条（Fiction Mode、Task、Instructions 等）。这些是帮你规范 AI 行为的默认指令，你现在可以先不管它们，等更熟悉之后再按需修改或删除。</p><p>我们来创建自己的词条。确保你在 <strong>PRESETS</strong> 分组下，点右上角的 <strong>添加词条（+ Add Entry）</strong>。</p><p>在这个游戏里，AI 不是某个角色，而是<strong>游戏主持人（GM）</strong>——负责描述场景、扮演所有 NPC、推动剧情。所以第一个词条就是告诉 AI 它的身份和职责。</p><p><img src="'+o+`" alt="创建角色设定词条"></p><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>名称（Name）</strong></td><td><code>游戏主持人设定</code></td></tr><tr><td><strong>发送身份（Send as）</strong></td><td><code>Instruction</code>（指令——AI 会把这当成规则来遵守）</td></tr><tr><td><strong>标签（Tags）</strong></td><td>点 <code>Preset</code></td></tr></tbody></table><p>在 <strong>内容（Content）</strong> 里写：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一个公正的恐怖生存游戏GM。游戏持续14天（14个夜晚）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>设定：末日降临，城市中出现了外表酷似人类的”访客”。玩家独自在家，每晚会有人来敲门求助。玩家需要通过门上的猫眼观察、对话盘问等方式判断来者的真实身份，决定是否开门。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你的职责：</span></span>
<span class="line"><span>- 每个夜晚描述敲门者的外貌、言行</span></span>
<span class="line"><span>- 公平地给出线索，不直接揭露身份</span></span>
<span class="line"><span>- 白天让玩家自由探索房间、使用物品、打电话</span></span>
<span class="line"><span>- 保持悬疑紧张的氛围</span></span>
<span class="line"><span>- 在每次回复末尾给出3-5个建议选项（A/B/C/D/E格式）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每次回复以阶段标题开头，格式：</span></span>
<span class="line"><span>- 夜晚：**第X夜**</span></span>
<span class="line"><span>- 白天：**第X天**</span></span></code></pre></div><p>几个关键点：</p><ul><li>词条在 <strong>PRESETS</strong> 分组下 → 它会始终发送给 AI，每次对话都能看到。核心设定必须放这里</li><li><strong>Send as = Instruction</strong> → AI 会把这当成系统指令来遵守，不是角色对话</li><li><strong>Tag = Preset</strong> → 方便分类管理</li></ul><p>这个词条就是你游戏的”宪法”——定义了 AI 的一切行为准则。</p><hr><h2 id="第三步-写开场白" tabindex="-1">第三步：写开场白 <a class="header-anchor" href="#第三步-写开场白" aria-label="Permalink to &quot;第三步：写开场白&quot;">​</a></h2><p>切换到 <strong>开场白（First Message）</strong> 区域，点 <strong>添加开场白（Add Greeting）</strong>。（或者在 Lorebook 里新建一个 <code>role: greeting</code> 的词条，效果一样。）</p><p><img src="`+r+`" alt="编辑开场白"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>**第1夜**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>电视里的雪花噪点闪烁不停。应急广播用机械般的声音重复着同一段警告：&quot;……目前已确认的访客特征：牙齿过于整齐划一，呈瓷白色。请居民注意甄别，切勿轻易开门……&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你独自待在家里。房子不大，有浴室、客厅、卧室、书房、厨房和储物间。门上有一个猫眼，储物间里有一把手枪，书房有一部座机电话。冰箱里还有几天的食物。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>窗外的街道空无一人。或者说——看上去空无一人。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>然后，敲门声响了。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>***咚……咚……咚。***</span></span>
<span class="line"><span></span></span>
<span class="line"><span>门外传来一个年轻女人的声音，带着哭腔：&quot;求求你……让我进去吧……外面有东西在追我……&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**建议选项：**</span></span>
<span class="line"><span>A. 打开门让她进来</span></span>
<span class="line"><span>B. 隔着门和她说话，问几个问题</span></span>
<span class="line"><span>C. 拒绝，让她离开</span></span>
<span class="line"><span>D. 通过猫眼仔细观察她</span></span>
<span class="line"><span>E. 其他（输入你想做的任何事）</span></span></code></pre></div><p>开场白的要点：</p><ol><li>让玩家立刻知道自己在什么处境</li><li>交代可用的资源和环境</li><li>用一个需要决策的场景结尾，逼玩家马上行动</li></ol><hr><h2 id="第四步-创建游戏变量" tabindex="-1">第四步：创建游戏变量 <a class="header-anchor" href="#第四步-创建游戏变量" aria-label="Permalink to &quot;第四步：创建游戏变量&quot;">​</a></h2><p>切换到 <strong>变量（Variables）</strong> 区域，点 <strong>添加变量（Add Variable）</strong>，创建 5 个变量。</p><p><img src="`+d+`" alt="创建变量"></p><h3 id="_1-生命值" tabindex="-1">1. 生命值 <a class="header-anchor" href="#_1-生命值" aria-label="Permalink to &quot;1. 生命值&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>ID</strong></td><td><code>player_hp</code></td></tr><tr><td><strong>显示名称（Display Name）</strong></td><td><code>Player HP</code></td></tr><tr><td><strong>类型（Type）</strong></td><td><code>Number</code></td></tr><tr><td><strong>默认值（Default Value）</strong></td><td><code>3</code></td></tr><tr><td><strong>最小值（Min）</strong></td><td><code>0</code></td></tr><tr><td><strong>最大值（Max）</strong></td><td><code>5</code></td></tr><tr><td><strong>分类（Category）</strong></td><td><code>Stat</code></td></tr><tr><td><strong>行为规则（Behavior Rules）</strong></td><td><code>被访客攻击或做出致命错误时 -1。让 Pale Stranger 进门或承认自己独自一人时直接归零（即死）。降到 0 游戏结束。</code></td></tr></tbody></table><h3 id="_2-体力" tabindex="-1">2. 体力 <a class="header-anchor" href="#_2-体力" aria-label="Permalink to &quot;2. 体力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>ID</strong></td><td><code>energy_current</code></td></tr><tr><td><strong>显示名称（Display Name）</strong></td><td><code>Energy</code></td></tr><tr><td><strong>类型（Type）</strong></td><td><code>Number</code></td></tr><tr><td><strong>默认值（Default Value）</strong></td><td><code>3</code></td></tr><tr><td><strong>最小值（Min）</strong></td><td><code>0</code></td></tr><tr><td><strong>最大值（Max）</strong></td><td><code>8</code></td></tr><tr><td><strong>分类（Category）</strong></td><td><code>Resource</code></td></tr><tr><td><strong>行为规则（Behavior Rules）</strong></td><td><code>检查访客（body check）和射击消耗 1 点。猫眼观察和对话免费。白天恢复到上限。体力为 0 时无法执行消耗体力的行动。</code></td></tr></tbody></table><h3 id="_3-天数" tabindex="-1">3. 天数 <a class="header-anchor" href="#_3-天数" aria-label="Permalink to &quot;3. 天数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>ID</strong></td><td><code>game_day</code></td></tr><tr><td><strong>显示名称（Display Name）</strong></td><td><code>Game Day</code></td></tr><tr><td><strong>类型（Type）</strong></td><td><code>Number</code></td></tr><tr><td><strong>默认值（Default Value）</strong></td><td><code>1</code></td></tr><tr><td><strong>最小值（Min）</strong></td><td><code>1</code></td></tr><tr><td><strong>最大值（Max）</strong></td><td><code>14</code></td></tr><tr><td><strong>分类（Category）</strong></td><td><code>Stat</code></td></tr><tr><td><strong>行为规则（Behavior Rules）</strong></td><td><code>每完成一个完整的夜晚-白天周期后 +1。到第 14 天结束时游戏结算。</code></td></tr></tbody></table><h3 id="_4-阶段" tabindex="-1">4. 阶段 <a class="header-anchor" href="#_4-阶段" aria-label="Permalink to &quot;4. 阶段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>ID</strong></td><td><code>game_phase</code></td></tr><tr><td><strong>显示名称（Display Name）</strong></td><td><code>Game Phase</code></td></tr><tr><td><strong>类型（Type）</strong></td><td><code>String</code></td></tr><tr><td><strong>默认值（Default Value）</strong></td><td><code>Night</code></td></tr><tr><td><strong>分类（Category）</strong></td><td><code>Flag</code></td></tr><tr><td><strong>行为规则（Behavior Rules）</strong></td><td><code>值为 &quot;Night&quot; 或 &quot;Day&quot;。夜晚处理敲门事件，白天自由探索房间、使用物品。</code></td></tr></tbody></table><h3 id="_5-是否武装" tabindex="-1">5. 是否武装 <a class="header-anchor" href="#_5-是否武装" aria-label="Permalink to &quot;5. 是否武装&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>ID</strong></td><td><code>player_has_gun</code></td></tr><tr><td><strong>显示名称（Display Name）</strong></td><td><code>Has Gun</code></td></tr><tr><td><strong>类型（Type）</strong></td><td><code>Boolean</code></td></tr><tr><td><strong>默认值（Default Value）</strong></td><td><code>True</code></td></tr><tr><td><strong>分类（Category）</strong></td><td><code>Flag</code></td></tr><tr><td><strong>行为规则（Behavior Rules）</strong></td><td><code>玩家默认有手枪。射击访客消耗 1 点体力，但可能误杀人类。射击后需要描述后果。</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">行为规则是什么</p><p><strong>行为规则（behaviorRules）</strong> 不是代码，是写给 AI 看的自然语言提示。AI 生成回复时会读到这些，知道什么时候该改什么变量。相当于给 AI 的&quot;小抄&quot; φ(&gt;ω&lt;*)</p></div><hr><h2 id="第五步-变量是怎么变化的" tabindex="-1">第五步：变量是怎么变化的 <a class="header-anchor" href="#第五步-变量是怎么变化的" aria-label="Permalink to &quot;第五步：变量是怎么变化的&quot;">​</a></h2><p>你可能在想——变量创建好了，AI 怎么知道什么时候该改它们？</p><p><strong>好消息：你不需要手动教 AI。</strong> 只要你的世界里有变量，Yumina 引擎会自动做两件事：</p><ol><li><strong>自动告诉 AI 指令格式</strong>：引擎会在每次对话时悄悄塞一段说明给 AI，教它用 <code>[变量ID: 操作 值]</code> 的格式来更新状态。你完全不用操心这个。</li><li><strong>自动把你写的行为规则发给 AI</strong>：上一步你在每个变量里填的&quot;行为规则&quot;，AI 每次都能看到。它会根据这些规则自己判断什么时候该改什么变量。</li></ol><p>举个例子：你在 <code>health</code> 变量的行为规则里写了&quot;被访客攻击或做出危险行为时扣减&quot;。当游戏中玩家被攻击了，AI 自己就会在回复末尾写出 <code>[health: -20]</code>，引擎检测到后自动把生命值从 100 减到 80。</p><p><strong>所以行为规则写得越清楚，AI 表现越好。</strong> 回去看看你第四步写的行为规则，确保每个变量都说清楚了&quot;什么情况下会变化、怎么变化&quot;。</p><div class="tip custom-block"><p class="custom-block-title">AI 输出的指令长什么样</p><p>AI 回复的末尾会出现类似这样的内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[health: -20]</span></span>
<span class="line"><span>[energy: -15]</span></span></code></pre></div><p>这些就是指令。引擎会自动提取并执行，玩家看到的回复里不会显示这些方括号内容。</p></div><div class="info custom-block"><p class="custom-block-title">更多指令语法</p><p>除了 <code>+</code>（加）和 <code>-</code>（减），还支持 <code>set</code>（设为指定值）、<code>toggle</code>（开关取反）等操作。详见 → <a href="./05-directives-and-macros.html">AI 指令与宏</a></p></div><hr><h2 id="第六步-让世界好看一点——用-ai-生成界面" tabindex="-1">第六步：让世界好看一点——用 AI 生成界面 <a class="header-anchor" href="#第六步-让世界好看一点——用-ai-生成界面" aria-label="Permalink to &quot;第六步：让世界好看一点——用 AI 生成界面&quot;">​</a></h2><p>到这一步，你的世界已经能玩了。但玩家只能看到纯文字——没有氛围，没有沉浸感。我们来做一个真正有恐怖游戏感觉的界面。</p><p>&quot;写代码？&quot; 不不不，让 AI 帮你写就行 (￣▽￣)ノ</p><h3 id="方法一-用-yumina-内置的-studio-ai-推荐" tabindex="-1">方法一：用 Yumina 内置的 Studio AI（推荐） <a class="header-anchor" href="#方法一-用-yumina-内置的-studio-ai-推荐" aria-label="Permalink to &quot;方法一：用 Yumina 内置的 Studio AI（推荐）&quot;">​</a></h3><ol><li>点编辑器顶部的 <strong>进入 Studio（Enter Studio）</strong></li><li>打开 <strong>AI Assistant</strong> 面板</li><li>把下面这段发给它（你可以直接复制）：</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我做一个末日恐怖生存游戏风格的消息渲染器。参考游戏 &quot;No, I&#39;m not a Human&quot; 的风格。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我需要这些效果：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 相位标题：</span></span>
<span class="line"><span>   - 如果 AI 回复里有 &quot;🌑 **NIGHT X**&quot;，提取出来做成一个 CRT 显示器风格的标题栏（深绿色发光文字、扫描线效果、轻微闪烁）</span></span>
<span class="line"><span>   - 如果有 &quot;☀️ **DAY X**&quot;，做成暖色调的标题栏（琥珀色文字）</span></span>
<span class="line"><span>   - 标题从消息正文里去掉，单独展示</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 敲门效果：</span></span>
<span class="line"><span>   - 如果回复里有 ***加粗斜体的文字***（三个星号包裹），把它们提取出来做成敲门动画——大号红色文字，有抖动效果</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 底部 HUD 状态栏：</span></span>
<span class="line"><span>   - 用等宽字体，暗绿色背景</span></span>
<span class="line"><span>   - 显示：⚡ 体力（energy_current 变量）、❤️ HP（player_hp 变量）、🔫/🚫 武装状态（player_has_gun 变量）</span></span>
<span class="line"><span>   - 紧凑的一行显示</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 叙事文本区域：</span></span>
<span class="line"><span>   - 暗色背景（深绿黑色），有微弱的边框发光</span></span>
<span class="line"><span>   - 浅绿色文字，行间距大一点，有阅读感</span></span>
<span class="line"><span>   - 用 renderMarkdown 渲染</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 选择按钮：</span></span>
<span class="line"><span>   - 如果 AI 回复里有 &quot;Suggested Choices:&quot; 或 &quot;**你的选择：**&quot;，把选项（A. B. C. D. E.）提取出来做成可点击的按钮</span></span>
<span class="line"><span>   - 点击后自动发送对应选项</span></span>
<span class="line"><span>   - 暗绿色调，hover 变亮</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 整体氛围：黑绿色 CRT 监控器风格，低饱和度，压抑的末日感</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我的变量：</span></span>
<span class="line"><span>- player_hp — 生命值，数字，0-5</span></span>
<span class="line"><span>- energy_current — 体力，数字，0-8</span></span>
<span class="line"><span>- game_day — 第几天，数字，1-14</span></span>
<span class="line"><span>- game_phase — &quot;Night&quot; 或 &quot;Day&quot;</span></span>
<span class="line"><span>- player_has_gun — 是否有枪，是/否</span></span></code></pre></div><ol start="4"><li>AI 会生成代码并弹出审核卡片，Canvas 面板可以实时看到效果</li><li>满意就点 <strong>批准（Approve）</strong>，不满意就继续说&quot;敲门效果再夸张一点&quot;或&quot;选择按钮间距太大了&quot;</li></ol><p><img src="`+p+'" alt="Studio AI 生成界面"></p><p><img src="'+l+`" alt="生成的效果预览"></p><p>你看，这样一个酷炫的前端就怎么简单的搭建好了！！！</p><h3 id="方法二-用外部-ai-claude、chatgpt-等" tabindex="-1">方法二：用外部 AI（Claude、ChatGPT 等） <a class="header-anchor" href="#方法二-用外部-ai-claude、chatgpt-等" aria-label="Permalink to &quot;方法二：用外部 AI（Claude、ChatGPT 等）&quot;">​</a></h3><p>如果你更习惯用其他 AI，也完全可以。把上面的效果描述发给它，末尾加上 Yumina 的技术信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yumina 技术信息（写代码时请遵守）：</span></span>
<span class="line"><span>- 代码格式 TSX，用 export default function Renderer({ content, renderMarkdown }) { ... } 导出</span></span>
<span class="line"><span>- useYumina() 可以拿到变量，比如 useYumina().variables.player_hp</span></span>
<span class="line"><span>- useYumina().sendMessage(text) 可以以玩家身份发送消息（做可点击选项用）</span></span>
<span class="line"><span>- 内置 Icons 图标库（不用 import），比如 Icons.Heart, Icons.Zap</span></span>
<span class="line"><span>- renderMarkdown(content) 把文字变成带格式的 HTML</span></span>
<span class="line"><span>- 支持 Tailwind CSS 和 React hooks</span></span>
<span class="line"><span>- 注入动画用 useEffect + document.createElement(&quot;style&quot;)</span></span>
<span class="line"><span>- 用 var 不用 const/let 做顶层声明</span></span></code></pre></div><p>AI 给你代码后：</p><ol><li>回到编辑器 → <strong>消息渲染器（Message Renderer）</strong> 区域 → 选 <strong>自定义 TSX（Custom TSX）</strong></li><li>把代码粘贴进去</li><li>底部显示 <strong>编译状态：OK（Compile Status: OK）</strong> 就说明成功了</li></ol><div class="tip custom-block"><p class="custom-block-title">代码不用看懂</p><p>你不需要理解这些代码在干什么。只要粘贴进去后底部显示 <strong>编译状态：OK（Compile Status: OK）</strong> 就说明没问题。如果报错了，把错误信息原封不动发回给 AI 让它修就行 ∠( ᐛ 」∠)＿</p></div><div class="tip custom-block"><p class="custom-block-title">不满意怎么办</p><p>效果不是你想要的？直接跟 AI 说&quot;血条太细了加粗一点&quot;、&quot;背景换成纯黑&quot;、&quot;加个闪烁效果&quot;之类的，让它修改再重新粘贴。来回几轮就能调到你满意为止。</p></div><hr><h2 id="第七步-写世界书词条" tabindex="-1">第七步：写世界书词条 <a class="header-anchor" href="#第七步-写世界书词条" aria-label="Permalink to &quot;第七步：写世界书词条&quot;">​</a></h2><p>前面的词条放在 <strong>PRESETS</strong> 分组，始终发送。但有些信息只在相关话题出现时才需要——这就是 <strong>CHAT HISTORY</strong> 分组的用途。</p><p>回到 <strong>词条（Lorebook）</strong>，展开左侧的 <strong>CHAT HISTORY</strong> 分组，在这个分组下点 <strong>添加词条（+ Add Entry）</strong> 创建几个关键词触发的词条：</p><h3 id="_1-敲门事件规则" tabindex="-1">1. 敲门事件规则 <a class="header-anchor" href="#_1-敲门事件规则" aria-label="Permalink to &quot;1. 敲门事件规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>名称（Name）</strong></td><td><code>敲门事件</code></td></tr><tr><td><strong>发送身份（Send as）</strong></td><td><code>Instruction</code></td></tr><tr><td><strong>关键词（Keywords）</strong></td><td><code>门</code>, <code>敲门</code>, <code>开门</code>, <code>knock</code></td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>敲门事件处理规则：</span></span>
<span class="line"><span>- 每个夜晚有2-3个敲门者，依次出现</span></span>
<span class="line"><span>- 玩家可以：通过猫眼观察（免费）、隔门对话（免费）、要求身体检查（消耗体力）、开门或拒绝</span></span>
<span class="line"><span>- 让人类进来 = 有的能帮忙 | 让访客进来 = 危险</span></span>
<span class="line"><span>- 描述敲门场景时保持悬疑，不直接揭露身份</span></span></code></pre></div><h3 id="_2-猫眼观察" tabindex="-1">2. 猫眼观察 <a class="header-anchor" href="#_2-猫眼观察" aria-label="Permalink to &quot;2. 猫眼观察&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>名称（Name）</strong></td><td><code>猫眼观察</code></td></tr><tr><td><strong>发送身份（Send as）</strong></td><td><code>Instruction</code></td></tr><tr><td><strong>关键词（Keywords）</strong></td><td><code>猫眼</code>, <code>窥视</code>, <code>观察</code>, <code>看看</code></td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>猫眼观察规则：</span></span>
<span class="line"><span>- 只能看到门外来者的头部和上半身</span></span>
<span class="line"><span>- 重点描述：面部表情、牙齿、眼睛、皮肤质感</span></span>
<span class="line"><span>- 访客的伪装有细微破绽（牙齿过于整齐、瞳孔不正常、皮肤纹理异样）</span></span>
<span class="line"><span>- 人类有正常的不完美特征（龋齿、黑眼圈、伤疤）</span></span>
<span class="line"><span>- 不要直接揭露身份，只描述画面</span></span></code></pre></div><h3 id="_3-房间搜索" tabindex="-1">3. 房间搜索 <a class="header-anchor" href="#_3-房间搜索" aria-label="Permalink to &quot;3. 房间搜索&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td><strong>名称（Name）</strong></td><td><code>搜索房间</code></td></tr><tr><td><strong>发送身份（Send as）</strong></td><td><code>Instruction</code></td></tr><tr><td><strong>关键词（Keywords）</strong></td><td><code>搜索</code>, <code>检查</code>, <code>翻找</code>, <code>探索</code>, <code>房间</code></td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>房间搜索规则（仅白天可用）：</span></span>
<span class="line"><span>- 储物间：可以找到手枪</span></span>
<span class="line"><span>- 厨房：食物补给，可以恢复少量体力</span></span>
<span class="line"><span>- 书房：电话，可以拨打获取情报</span></span>
<span class="line"><span>- 描述环境细节，营造不安氛围</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">关键词触发的原理</p><p>引擎每次生成回复前，会扫描最近几条消息。出现匹配关键词 → 对应词条临时发给 AI。没人提到 → AI 看不到，不浪费阅读量。又省空间又精准 (≧▽≦)</p><p>扫描深度在 <strong>词条（Lorebook）</strong> 区域的 <strong>Entry Settings</strong> 里的 <code>Scan Depth</code> 设置，默认 2，建议改到 4。</p></div><hr><h2 id="第八步-测试" tabindex="-1">第八步：测试 <a class="header-anchor" href="#第八步-测试" aria-label="Permalink to &quot;第八步：测试&quot;">​</a></h2><p>核心内容都搞定了，测试一下！</p><p>先点编辑器顶部的 <strong>保存（Save）</strong>，然后点左侧导航栏底部的金色 <strong>PLAY</strong> 按钮。在弹出的会话界面点 <strong>新建会话（New Session）</strong>，检查以下几项：</p><table tabindex="0"><thead><tr><th>检查项</th><th>怎么验证</th><th>没生效的话</th></tr></thead><tbody><tr><td>开场白显示</td><td>进入后自动出现第一条消息</td><td>检查 First Message 区域是否写了开场白</td></tr><tr><td>渲染器生效</td><td>消息有 CRT 风格的相位标题和 HUD</td><td>检查 Message Renderer 是否选了 Custom TSX 且编译 OK</td></tr><tr><td>指令生效</td><td>互动后变量会跟着变（HUD 数值变化）</td><td>检查变量的行为规则是否写清楚了</td></tr><tr><td>世界书触发</td><td>提到&quot;猫眼&quot;后 AI 按规则描述</td><td>检查关键词拼写、Scan Depth 设置</td></tr></tbody></table><hr><h2 id="第九步-完善概览信息" tabindex="-1">第九步：完善概览信息 <a class="header-anchor" href="#第九步-完善概览信息" aria-label="Permalink to &quot;第九步：完善概览信息&quot;">​</a></h2><p>测试没问题了，切到 <strong>概览（Overview）</strong> 区域，把发布前的信息填好：</p><ol><li>上传一张 <strong>封面图（Cover Image）</strong>（能体现恐怖氛围的）</li><li>写一段 <strong>描述（Description）</strong>，让玩家知道这是什么游戏</li><li>加 <strong>标签（Tags）</strong>：<code>恐怖</code>, <code>生存</code>, <code>解谜</code>, <code>互动小说</code></li><li>设置 <strong>语言（Language）</strong>：选择你的世界是什么语言写的（比如 <code>中文</code>）</li><li>点编辑器顶部的 <strong>保存（Save）</strong></li></ol><p><img src="`+i+'" alt="概览信息"></p><hr><h2 id="第十步-发布" tabindex="-1">第十步：发布 <a class="header-anchor" href="#第十步-发布" aria-label="Permalink to &quot;第十步：发布&quot;">​</a></h2><ol><li>回到左侧导航栏的 <strong>发现（Discover）</strong> 页面</li><li>点顶部的 <strong>发布（Publish）</strong> 按钮</li><li>在弹出的发布弹窗中选择你的世界</li><li>设置年龄分级、可见性、是否允许别人编辑</li><li>勾选同意条款，点发布</li></ol><p>完事了！你的世界上线了 ヽ(✿ﾟ▽ﾟ)ノ</p><hr><h2 id="你学到了什么" tabindex="-1">你学到了什么 <a class="header-anchor" href="#你学到了什么" aria-label="Permalink to &quot;你学到了什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>你做了什么</th></tr></thead><tbody><tr><td><strong>词条</strong></td><td>写了系统设定和开场白——AI 行为的基础</td></tr><tr><td><strong>变量</strong></td><td>创建了 HP、体力、天数——游戏状态的骨架</td></tr><tr><td><strong>指令</strong></td><td>引擎自动教 AI 用指令更新状态，你只需要写好行为规则</td></tr><tr><td><strong>自定义界面</strong></td><td>用 AI 生成了状态面板——不用自己写代码</td></tr><tr><td><strong>世界书</strong></td><td>关键词触发的规则词条——按需加载的知识库</td></tr></tbody></table><p>这五样东西配合起来，就是一个完整的互动世界。</p><h2 id="还能做什么" tabindex="-1">还能做什么 <a class="header-anchor" href="#还能做什么" aria-label="Permalink to &quot;还能做什么&quot;">​</a></h2><p>这篇教程只用了最基础的功能。Yumina 还有很多好玩的：</p><ul><li><strong><a href="./06-rules-engine.html">行为规则引擎</a></strong> — HP 降到 0 自动触发死亡结局，不用等 AI 自觉</li><li><strong><a href="./08-message-renderer.html">自定义渲染器</a></strong> — 把消息变成气泡对话、视觉小说、战斗日志</li><li><strong><a href="./09-audio.html">音频系统</a></strong> — 加 BGM 和音效，进地下室自动切阴间音乐</li><li><strong><a href="./03-entries-and-lorebook.html">条件词条</a></strong> — 根据变量值激活词条，比如后期才出现的剧情</li></ul><p><strong>进阶教程</strong>（以&quot;壺中の毒 · 大逃杀&quot;为蓝本）即将推出，会深入讲行为引擎、自定义渲染器和复杂状态管理。</p><hr><h2 id="去玩真实版" tabindex="-1">去玩真实版 <a class="header-anchor" href="#去玩真实版" aria-label="Permalink to &quot;去玩真实版&quot;">​</a></h2><p>这篇教程做的是简化版——5 个变量、几条词条、一个渲染器。但 Yumina 上的真实 &quot;No, I&#39;m not a Human&quot; 完整卡有：</p><ul><li><strong>20+ 个角色</strong>：8 个人类（收银员 Sarah、退休工程师 Marcus、护士 Elena……）、6 个伪装成人类的访客（送货员 Jake、小女孩 Lily……）、还有特殊角色（Pale Stranger、神秘的 Who、猫婆婆）</li><li><strong>25+ 个变量</strong>：不只是血量和体力——还有房间状态、客人记录、FEMA 通报次数、各种库存（咖啡、能量饮料、猫粮……）</li><li><strong>完整的猫眼系统</strong>：透过猫眼看到每个角色的立绘，人类有正常瑕疵，访客有细微破绽</li><li><strong>CRT 监控器风格渲染器</strong>：夜晚/白天相位动画、敲门抖动效果、可点击选择按钮、底部 HUD</li></ul><p>去 <a href="https://yumina.io" target="_blank" rel="noreferrer">yumina.io</a> 搜索 <strong>&quot;No, I&#39;m not a Human&quot;</strong> 体验完整版，感受一下你的世界能做到什么程度。然后回来继续打磨你自己的作品 ᕕ( ᐛ )ᕗ</p>',111)])])}const v=s(c,[["render",g]]);export{k as __pageData,v as default};
